// Transform Webhook Payload - V2 (Multi-Format Support)
// Unterstützt: Supabase Webhook, Direct POST, curl, n8n HTTP Request

const input = $input.first().json;
let record = null;
let source = 'webhook';

// ============================================
// FORMAT 1: Supabase Database Webhook
// Struktur: { type: 'INSERT', table: 'events', record: {...} }
// ============================================
if (input.type === 'INSERT' && input.record) {
  record = input.record;
  source = 'supabase_webhook';
}

// ============================================
// FORMAT 2: Direct POST (curl, Postman, andere Flows)
// Struktur: { event_id, event_type, project_id, payload }
// ============================================
else if (input.event_id && input.event_type) {
  record = {
    id: input.event_id,
    event_type: input.event_type,
    project_id: input.project_id,
    payload: input.payload || {},
    created_at: input.created_at || new Date().toISOString(),
    source_system: input.source_system || 'manual',
    source_flow: input.source_flow || 'direct_post'
  };
  source = 'direct_post';
}

// ============================================
// FORMAT 3: n8n Webhook Body Wrapper
// Struktur: { body: { event_id, event_type, ... } }
// ============================================
else if (input.body?.event_id && input.body?.event_type) {
  record = {
    id: input.body.event_id,
    event_type: input.body.event_type,
    project_id: input.body.project_id,
    payload: input.body.payload || {},
    created_at: input.body.created_at || new Date().toISOString(),
    source_system: input.body.source_system || 'n8n',
    source_flow: input.body.source_flow || 'webhook_body'
  };
  source = 'webhook_body';
}

// ============================================
// FORMAT 4: Supabase Webhook wrapped in body
// Struktur: { body: { type: 'INSERT', record: {...} } }
// ============================================
else if (input.body?.type === 'INSERT' && input.body?.record) {
  record = input.body.record;
  source = 'supabase_webhook_wrapped';
}

// ============================================
// FORMAT 5: Event-Objekt direkt (von Sweeper oder anderem Flow)
// Struktur: { id, event_type, project_id, payload, ... }
// ============================================
else if (input.id && input.event_type) {
  record = {
    id: input.id,
    event_type: input.event_type,
    project_id: input.project_id,
    payload: input.payload || {},
    created_at: input.created_at,
    source_system: input.source_system,
    source_flow: input.source_flow
  };
  source = 'event_object';
}

// ============================================
// OUTPUT
// ============================================
if (record && record.event_type) {
  return [{
    json: {
      id: record.id,
      event_type: String(record.event_type), // Ensure string for Switch
      project_id: record.project_id,
      payload: typeof record.payload === 'string' 
        ? JSON.parse(record.payload) 
        : (record.payload || {}),
      created_at: record.created_at,
      source_system: record.source_system,
      source_flow: record.source_flow,
      _meta: {
        source: source,
        detected_format: source,
        processed_at: new Date().toISOString()
      }
    }
  }];
}

// No valid record found - log and skip
console.log('Transform: No valid event format detected', JSON.stringify(input).substring(0, 500));
return [];

// Merge event with ALL routes (multi-route support)
const event = $('Transform Webhook Payload').first().json;
const routes = $input.all();

if (routes.length === 0) {
  return [{ json: { ...event, target_workflow: null, webhook_url: null, source: 'webhook' } }];
}

return routes.map(route => ({
  json: {
    ...event,
    target_workflow: route.json.target_workflow,
    webhook_url: route.json.webhook_url,
    source: 'webhook'
  }
}));

// Add source marker to sweeper items
const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    source: 'sweeper'
  }
}));

// Final output
const items = $input.all();

return items.map(item => ({
  json: {
    status: item.json.dispatch_status || 'processed',
    event_id: item.json.id,
    event_type: item.json.event_type,
    target_workflow: item.json.target_workflow,
    processed_at: item.json.processed_at
  }
}));

// Dynamic Route Dispatcher v2
// Dispatches to ALL routes, returns errors as separate items for DB logging

const items = $input.all();
const results = [];

for (const item of items) {
  const event = item.json;
  const webhookUrl = event.webhook_url;
  const targetWorkflow = event.target_workflow;

  if (!webhookUrl) {
    console.log('⏭️ Skipping - no webhook_url for:', event.event_type);
    continue;
  }

  const payload = {
    event_id: event.id,
    event_type: event.event_type,
    project_id: event.project_id,
    payload: event.payload
  };

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: webhookUrl,
      body: payload,
      json: true,
      timeout: 120000
    });

    results.push({
      json: {
        ...event,
        dispatch_status: 'success',
        _isError: false
      }
    });

    console.log(`✅ Dispatched to ${targetWorkflow}`);

  } catch (error) {
    const errorCode = error.code || 'UNKNOWN';
    const httpStatus = error.response?.status || null;

    results.push({
      json: {
        ...event,
        dispatch_status: 'error',
        _isError: true,
        _error: {
          event_id: event.id,
          event_type: event.event_type,
          target_workflow: targetWorkflow,
          webhook_url: webhookUrl,
          error_message: error.message,
          error_code: errorCode,
          http_status: httpStatus
        }
      }
    });

    console.error(`❌ Error dispatching to ${targetWorkflow}:`, error.message);
  }
}

return results.length > 0 ? results : [{ json: { status: 'no_routes_dispatched', _isError: false } }];

